var atriumSpaces = ['a1', 'a2', 'a3'];
var labelIndex = {};

atriumSpaces.forEach(function(sp) {
  (sections[sp] || []).forEach(function(row) {
    if (!labelIndex[row.labelId]) {
      labelIndex[row.labelId] = { labelId: row.labelId, displayName: row.displayName, spaces: {} };
    }
    labelIndex[row.labelId].spaces[sp] = true;
    if (!labelIndex[row.labelId].displayName && row.displayName) {
      labelIndex[row.labelId].displayName = row.displayName;
    }
  });
});

var allAtriums = Object.keys(labelIndex).map(function(labelId) {
  var rec = labelIndex[labelId];
  return { labelId: labelId, displayName: rec.displayName || labelId, spaces: Object.keys(rec.spaces) };
}).filter(function(rec) {
  return rec.spaces.length >= 2;
}).sort(function(a, b) {
  return String(a.displayName).localeCompare(String(b.displayName));
});

msg.topic = 'lighting/model';
msg.payload = { allAtriums: allAtriums, sections: sections };
return msg;

'use strict';

var p = msg.payload || {};
var action = p.action;

function makeFire(space, labelId) {
  return { payload: { action: 'fire', space: space, labelId: labelId } };
}

if (action === 'fire') {
  if (!p.space || !p.labelId) return null;
  return makeFire(p.space, p.labelId);
}

if (action === 'fireMany') {
  var spaces = Array.isArray(p.spaces) ? p.spaces : [];
  if (!p.labelId || spaces.length === 0) return null;

  // Explicitly emit one message per space
  spaces.forEach(function (sp) {
    node.send(makeFire(sp, p.labelId));
  });

  // Return nothing because we've already sent them
  return null;
}

return null;

// Example in a Node-RED function node
const actionMap = {
    "show_1": [
        { type: "watchout.timeline", action: "start", id: "show_1" },
        { type: "watchout", command: "startTimeline", timelineId: "show_1" },
        { type: "watchout", command: "fireCue", timelineId: "show_1", cueId: "cue_special" },
        { type: "ma.cue", action: "go", cue: "show_1_start" },
        { type: "ma.macro", macro: "FX_SHOT", params: { speed: 100 } },
        { type: "qsys", command: "recall_scene", scene: "Show1" },
        { type: "pharos", command: "trigger", triggerId: "show1_start" },
        { type: "pharos", system: "main", command: "trigger", triggerId: "main_scene_1" },
        { type: "pharos", system: "fountain", command: "setPreset", preset: "welcome" }
    ],
    "ambience_1": [
        { type: "watchout.timeline", action: "start", id: "ambience_1" },
        { type: "ma.cue", action: "go", cue: "ambience_1" },
        { type: "qsys", command: "set_bgm_loop", loop: "Amb1_BG" }
    ]
    // ...more shows/ambiances
};

msg.actions = actionMap[msg.payload.contentId]; // contentId from trigger
return msg;

// After initial mapping write: start sequential cue fetch for all timelines.
// Output 1: first cue fetch request → HTTP node
// Output 2: no timelines / skip → final file write

const mapping = flow.get('watchout_mapping') || {};
const cfg = flow.get('watchout_config') || {};
const baseUrl = 'http://' + (cfg.host || 'localhost') + ':' + (cfg.port || 3019);

const queue = Object.keys(mapping)
    .filter(key => mapping[key] && mapping[key].watchoutTimelineId)
    .map(key => ({ timelineKey: key, watchoutTimelineId: mapping[key].watchoutTimelineId }));

flow.set('watchout_cue_queue', queue);
flow.set('watchout_cue_index', 0);

if (queue.length === 0) {
    // No timelines to fetch cues for — write current mapping as-is
    msg.filename = cfg.mappingFile || '/projects/XYZ-Exit10/node-red/data/timeline-mapping.json';
    msg.payload = JSON.stringify(mapping, null, 2);
    msg._savedAt = new Date().toISOString();
    return [null, msg];
}

const first = queue[0];
msg.method = 'GET';
msg.url = baseUrl + '/v0/cues/' + encodeURIComponent(first.watchoutTimelineId);
msg._fetchTimelineKey = first.timelineKey;
msg.payload = null;
return [msg, null];

// Store cue result for the current timeline, then advance the loop.
// Output 1: next fetch request → HTTP node (loop)
// Output 2: all timelines processed → final file write

const timelineKey = msg._fetchTimelineKey;
const statusCode  = msg.statusCode || 200;

const mapping = flow.get('watchout_mapping') || {};
const cfg     = flow.get('watchout_config') || {};
const baseUrl = 'http://' + (cfg.host || 'localhost') + ':' + (cfg.port || 3019);

// Normalize cue name → cueKey (same rules as timeline names)
function normalizeName(name) {
    if (!name || String(name).startsWith('_')) return null;
    const key = String(name).trim().toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
    return key || null;
}

if (timelineKey && statusCode < 300) {
    const cueList = Array.isArray(msg.payload) ? msg.payload : [];
    const cues = {};
    cueList.forEach(c => {
        const cueKey = normalizeName(c.name);
        if (!cueKey) return; // skip cues with null or invalid names
        cues[cueKey] = {
            displayName: c.name,
            watchoutCueId: String(c.id)
        };
    });
    if (mapping[timelineKey]) {
        mapping[timelineKey].cues = cues;
    }
    flow.set('watchout_mapping', mapping);
}

// Advance queue
const queue = flow.get('watchout_cue_queue') || [];
let idx = (flow.get('watchout_cue_index') || 0) + 1;
flow.set('watchout_cue_index', idx);

if (idx < queue.length) {
    // More timelines to fetch
    const next = queue[idx];
    msg.method = 'GET';
    msg.url = baseUrl + '/v0/cues/' + encodeURIComponent(next.watchoutTimelineId);
    msg._fetchTimelineKey = next.timelineKey;
    msg.payload = null;
    return [msg, null]; // loop back to HTTP node
}

// All done — write final mapping with cues
msg.filename = cfg.mappingFile || '/projects/XYZ-Exit10/node-red/data/timeline-mapping.json';
msg.payload  = JSON.stringify(mapping, null, 2);
msg._savedAt = new Date().toISOString();
return [null, msg]; // to file write

// Build ui-dropdown options for the cues of the currently selected timeline.
// Triggered when the timeline selection changes or the mapping refreshes.

const mapping = flow.get('watchout_mapping') || {};
const timelineKey = flow.get('watchout_selected_timelineKey') || '';

const entry = mapping[timelineKey] || {};
const cues  = entry.cues || {};

const keys = Object.keys(cues).sort((a, b) => {
    const da = cues[a] && cues[a].displayName ? String(cues[a].displayName) : a;
    const db = cues[b] && cues[b].displayName ? String(cues[b].displayName) : b;
    return da.localeCompare(db);
});

let options;
let selected;

if (keys.length === 0) {
    options  = [{ value: '', label: timelineKey ? 'No cues (run Confirm & Save)' : 'Select a timeline first' }];
    selected = '';
} else {
    options  = keys.map(key => ({
        value: key,
        label: (cues[key].displayName || key) + ' [id ' + cues[key].watchoutCueId + ']'
    }));
    // Keep previous selection when possible
    const prev = flow.get('watchout_selected_cueKey');
    selected = (prev && cues[prev]) ? prev : options[0].value;
}

flow.set('watchout_selected_cueKey', selected);

msg.options  = options;
msg.payload  = selected;

node.status({ fill: keys.length ? 'green' : 'grey', shape: 'dot',
              text: timelineKey ? (keys.length + ' cues for ' + timelineKey) : 'no timeline' });
return msg;

// Store the selected cueKey for use by the Goto buttons.
flow.set('watchout_selected_cueKey', msg.payload);
return msg;

// Build a jumpToCue control payload from the currently selected timeline + cue.
// msg.payload: "goto" (paused) or "gotoPlay" (with state=play)

const action      = msg.payload;
const timelineKey = flow.get('watchout_selected_timelineKey');
const cueKey      = flow.get('watchout_selected_cueKey');

if (!timelineKey) {
    node.status({ fill: 'red', shape: 'ring', text: 'No timeline selected' });
    return null;
}
if (!cueKey) {
    node.status({ fill: 'red', shape: 'ring', text: 'No cue selected' });
    return null;
}

const cmd = { command: 'jumpToCue', timelineKey, cueKey };
if (action === 'gotoPlay') {
    cmd.state = 'play';
}

node.status({ fill: 'blue', shape: 'dot', text: action + ' ' + timelineKey + '/' + cueKey });

msg.payload = cmd;
return msg;
